{"code": "import re
import json

# Read the books data
books_file = var_functions.query_db:16
if isinstance(books_file, str) and books_file.endswith('.json'):
    with open(books_file, 'r') as f:
        books_data = json.load(f)
else:
    books_data = var_functions.query_db:16

# Extract publication year from details text
def extract_year(details):
    patterns = [
        r'(?:published|Published|released) on (\w+ \d{1,2}, \d{4})',
        r'(?:published|Published|released) on (\w+ \d{1,2} \d{4})',
        r'(?:published|Published|released) (\w+ \d{1,2}, \d{4})',
        r'(?:published|Published|released) (\d{4})',
        r'(?:January|February|March|April|May|June|July|August|September|October|November|December)[^\d]{0,20}(\d{4})',
        r'(\d{4}) edition',
        r'(\d{4})th edition'
    ]

    for pattern in patterns:
        match = re.search(pattern, details)
        if match:
            year_match = match.group(1)
            year_extract = re.search(r'(\d{4})', year_match)
            if year_extract:
                year = int(year_extract.group(1))
                if 1800 <= year <= 2023:
                    return year
    return None

# Process books
books_with_years = []
year_extraction_stats = {'success': 0, 'failed': 0}

for book in books_data:
    year = extract_year(book['details'])
    if year:
        decade = str(year//10*10) + 's'
        books_with_years.append({
            'book_id': book['book_id'],
            'year': year,
            'decade': decade
        })
        year_extraction_stats['success'] += 1
    else:
        year_extraction_stats['failed'] += 1

# Save results
with open('/tmp/books_with_years.json', 'w') as f:
    json.dump(books_with_years, f)

result = {
    'total_books': len(books_data),
    'books_with_years': len(books_with_years),
    'success_rate': year_extraction_stats['success'],
    'failed_rate': year_extraction_stats['failed']
}

print('__RESULT__:')
print(json.dumps(result))"}

